mapper.select:
select boardName, boardContent, readCount, boardNo, fk_categoryNo, createdAtBoard
from board 
where fk_categoryNo = #{categoryNo}

select C.categoryNo AS "categoryNo", C.categoryName AS "categoryName", C.categoryDescribe AS "categoryDescribe", C.categoryImagePath AS "categoryImagePath", COUNT(B.boardNo) AS "boardCount" from category C left join board B on B.fk_categoryNo = C.categoryNo
C.categoryNo = #{_parameter}
group by C.categoryNo, C.categoryName, C.categoryDescribe, C.categoryImagePath order by C.categoryNo
